const tx = $items('Create Transaction')[0].json;
const normalizedQuery = `search_query: ${tx.user_query.replace(/\s+/g, ' ').trim()}`;
return [{
  json: {
    ...tx,
    normalized_query: normalizedQuery,
    qdrant_collection: 'tpm_unite_history'
  }
}];

const tx = $items('Create Transaction')[0].json;
const normalized = $items('Normalize Query')[0].json.normalized_query;
const response = $json;
const statusCode = response.statusCode ?? response.status ?? 0;
const collectionExists = statusCode >= 200 && statusCode < 300 && !!response.body?.result;
const nextStatus = collectionExists ? 'retrieving' : 'refused';
const nextRetrievalStatus = collectionExists ? 'not_started' : 'no_context';
const refusalReason = collectionExists ? null : 'qdrant_collection_missing';
return [{
  json: {
    transaction_id: tx.transaction_id,
    user_query: tx.user_query,
    normalized_query: normalized,
    qdrant_collection: 'tpm_unite_history',
    qdrant_status_code: statusCode,
    collection_exists: collectionExists,
    retrieval_decision: collectionExists ? 'collection_available' : 'qdrant_collection_missing',
    next_status: nextStatus,
    next_retrieval_status: nextRetrievalStatus,
    refusal_reason: refusalReason,
    phase_1_result: collectionExists ? 'ready_for_phase_2_retrieval' : 'refused_missing_qdrant_collection'
  }
}];
